func supportStatuses() []string {
	return []string{"open", "triaged", "in_progress", "closed"}
}

func supportBackURL(isAdmin bool) templ.SafeURL {
	if isAdmin {
		return templ.SafeURL("/support-inbox")
	}
	return templ.SafeURL("/report-issue")
}

func supportBackLabel(isAdmin bool) string {
	if isAdmin {
		return "← Support inbox"
	}
	return "← All your reports"
}

func supportReportURL(iid string) templ.SafeURL {
	return templ.SafeURL("/report-issue/" + iid)
}

func supportRFC(u int64) string {
	return time.Unix(u, 0).UTC().Format(time.RFC3339)
}

func supportShort(u int64) string {
	return time.Unix(u, 0).UTC().Format("2006-01-02 15:04")
}

// supportStatusLabel maps the issue status to reporter-friendly wording.
func supportStatusLabel(s string) string {
	switch s {
	case "open":
		return "Open"
	case "triaged":
		return "Triaged"
	case "in_progress":
		return "In progress"
	case "closed":
		return "Resolved"
	}
	return s
}

func supportAuthor(c SupportCommentView) string {
	if c.IsMine {
		return "You"
	}
	if c.AuthorName == "" {
		return "Team"
	}
	return c.AuthorName
}

